use crate::codegen::TargetCore;

#[derive(Debug, Clone)]
pub struct DeviceInfo {
    pub name: &'static str,
    pub core: TargetCore,
    pub sram_start: u16,
    pub sram_size: u32,
    /// Total program flash in bytes (FLASHEND + 1). 0 = unknown.
    pub flash_size: u32,
    /// Total EEPROM in bytes (E2END + 1). 0 = unknown / none.
    pub eeprom_size: u32,
    /// Reserved bootloader (boot section) size in bytes. 0 = none / unknown.
    pub boot_size: u32,
}

